INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05690', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '關於「追分成功」，大家長期以來都誤解了。或者一廂情願地認定，這一中文字意在愛情上的美好結局。 我的理解剛好相反。「追分」一詞乃日本漢字，當時依鐵道鋪設，表示兩條線在此明顯分歧。成追線就 是這樣從成功站，清楚地分出了一條海線，跟縱貫線並行。追分成功真正的意思，或該闡述，人生不可 能圓滿，時有挫折衰蔽。許是愛情，許是事業，也可能是求學、謀職等等。當人生在重要關頭，做出轉 向或分離的抉擇時，如何不受傷又不害人，再次完美出發，或許才是這張車票的意義。上文對於「追分 成功」意義的闡述，下列選項何者正確？', '["在過程中，不畏懼挫折，勇敢朝目標前進", "在結局時，常保有謙虛，不忘挫敗的教訓", "在衰敗時，應積極以對，仍繼續追求圓滿", "在關鍵時，做適當選擇，並能重新再啟程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05691', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '我曾認識一個年輕人，多年後我在紐約遇見他，他開過計程車，做過跑堂，以及各式各樣的生存手段 ──他仍在認真地唸社會學，而且還在辦雜誌。一別數年，恍如隔世，但最安慰的是當我們一起走過曼 哈頓的市區，他無愧地說：「我還抱持著我當年那一點對人的關懷，對人的好奇，對人的執著。」下列 選項，何者最適合用來形容文中敘述的「他」？', '["正己而物正者也", "不失其赤子之心者也", "能見其過而內自訟者也", "臨事而懼，好謀而成者也"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05692', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「颱風每週到訪，很難處變不驚，臨危不亂。深夜裡，聽那足以摧棚掀瓦的十餘級風，肅殺之氣令人膽 寒。小時候讀『人定勝天』一語，興起豪情萬丈，現在我的想法是：人要知天、要順天；但天實難知難 順，人所做的一切努力，都是在試圖了解天地的存在及其莫測之變化，順其自然而已，偶或有些許突破， 千萬不可驕矜，因為那只不過是人類以其智慧，順乎天理而已。」根據上文，下列敘述符合題意的是：', '["作者認為傳統「人定勝天」的教育，是一種自欺欺人的說法", "作者認為人所做的一切努力，無法改變上天帶來的自然災害", "作者認為因為智慧，讓人們順應自然的變化，故能降低傷害", "作者認為人要順天而行，文中流露著一種悲觀、消極的想法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05693', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我身，這刻了舊痕的獨木舟，悠悠蕩蕩，仍在茫茫人海。往前，必然是叢林險路，疾病將如猛獸撲來。 我應當虛心接受。回首前塵，如此知足。」下列最符合作者表達意思的選項是：', '["身安處即心安處", "肉身如斑駁的獨木舟，當隨遇而安", "身體髮膚，受之父母，當細心照護", "人們之所以有大憂患，都是因為惦念著軀體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05694', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「秋還不那麼深，遇到多風的下午，野櫻依然搖擺細枝，那樣落拓地讓葉子一片一片跌到土地上，似乎 是沒有一絲怨尤的，帶著垂老的寧謐和果敢，也沒有任何拒斥或介入的神色，對時間完全漠然；歲月悠 悠，有情天地裏獨多一種無情，一種放棄。然而我又設想，寒冷的土地裏，誰說它那堅持的鬚根不又向 下延伸了三尺？」根據上文，關於野櫻的敘述，下列何者正確？', '["漠視大地的春去秋來", "孤獨地等待枯萎零落", "泰然面對生命的起落", "無奈地接受季節流轉 請依下文回答第19題至第20題： 「旅行者，需要許多條件。條件之一，就是須有一副好脾胃。……由北方觀點來看，閩粵人確實吃得太寬，也 吃得可怕。明朝謝肇淛《五雜俎》卷九論南人口味時說：『南人口食可謂不擇之甚。嶺南蟻卵蚺蛇皆為珍膳。 水雞蝦蟆其實一類。閩有龍虱者，飛來田中，與灶蟲分毫無別。又有土筍者，全類蚯蚓。擴而充之，天下殆無 不可食之物。』跟王侃的講法差不多，都是在說閩粵人吃得太雜。可是，謝肇淛自己是福建人，他立刻就自覺 到這樣的說法也不見得公允。因為北方人同樣有令南方人感到難以消受的食物。所以他說：『燕齊之人食蝎及 蝗。余行部至安丘，一門人家取草蟲有子者，炸黃色入饌。余詫之，歸語從吏。云此中珍品也，名蛐子，縉紳 中尤雅嗜之。然余終不敢食也。則蠻方有食毛蟲蜜唧者又何足怪？』這個辯護很有趣，足見南方人北方人半斤 八兩。……可是，往往就是那令遠方來的人無法欣賞的東西，才最足以代表那個地方的特色。」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05695', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中引用《五雜俎》之說，意思接近於：', '["南人嘴巴刁鑽，極為挑食", "南人善於取材，巧於烹飪", "南人脾胃強健，口慾較強", "南人口味特別，敢嘗異食"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05696', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '承上題，面對南北不同的飲食，作者認為旅行者應該要：', '["以美食家的嘴，盡情享受食物的鮮甜酥脆", "了解旅行的精神貴在互相包容、多方品嚐", "避免用負面眼光下判斷，破壞出遊的興致", "喜歡當地的美味料理，學習不同的烹調法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05697', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '情境：「林先生忙於上班兼差，與子女相處時間少，孩子都怕林先生，林先生感慨
自身學歷低只有微薄的薪資，對子女學習給予很大的壓力與期望，最近國小二年級
的長子考試成績不佳，被父親打了一頓之後，隔天沒有到學校上課，林太太打電話
給社工請求協助」，請用「任務中心取向的工作模式」，就問題處理目標、任務、
執行潛在阻礙與問題排除等項，申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05698', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '評估（assessment）或稱為評量，是社會工作專業服務中一項關鍵性專業活動。社
區工作（community work）作為助人專業活動，如同個案工作、團體工作，在專業
服務計畫之擬定中必須經過評估的歷程，請問在社區工作中評估社區能力上，主要
評估那些面向？請申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05699', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社區工作是一種計畫性的工作，其目的在於建構可增進社區居民改善其生活品質之能力的資產，其中主 張從發掘社區能力和資產介入模式稱為能力/資產路徑。下列有關以能力/資產路徑回應社區困境的敘述， 何者錯誤？', '["發展策略：始於社區缺乏的事務", "主要途徑：由下而上/由內而外", "居民角色：參與者、行動者", "關係導向：內部關係導向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
